var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"관측이 성공했다고? 그럼 낙원을 찾은 거야?","JPN":"観測に成功した？　つまり楽園を見つけたってこと？","ENG":"You found one? You really found the Promised Land?","TWN":"觀測成功了？那就是說找到了樂園？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그러엄-","JPN":"そーよー","ENG":"Of course.","TWN":"是啊——"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"수 세기에 걸쳐 관측 끝에 찾아낸, 모든 선별 조건에 부합하는 이상향이야.","JPN":"観測に数世紀もかけて、ついにすべての条件を完璧に満たす理想郷が見つかったのよ。","ENG":"After centuries of observations, we found a utopia that meets all the conditions.","TWN":"這是經過數個世紀的觀測，找到的符合所有篩選條件的烏托邦。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"사람을 전송하려면 아직 몇 가지 과제가 남았지만, 가설을 증명한 아주 뜻깊은 날이지.","JPN":"実際に人を送りこむには、まだ少し課題は残っているけれど、仮説が証明されただけでも非常に意味のある日になったわ。","ENG":"Although there are several tasks left before we can transfer people over there, today is a meaningful day of proving a hypothesis.","TWN":"雖然要傳送人類還有一些課題，但今天是證明了假設，非常有意義的一天。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그래서 내가 온 줄도 모를 정도로 취해있던 거야?","JPN":"それで、あたしが来たことにも気づかないぐらい酔うまで飲んでいたの？","ENG":"Is that why you were so drunk that you didn't know that I came to see you?","TWN":"所以你喝得連我來了都不知道？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"아하항- 딸꾹.","JPN":"あひゃひゃ……ひくっ。","ENG":"Ah hah hah... *Hiccup*","TWN":"哈哈哈——嗝。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"하…","JPN":"はぁ……","ENG":"*Sigh*","TWN":"哀…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"가시너울 숲에 마물이 쳐들어왔어.","JPN":"ウネリトゲの森に魔物が攻めてきたわ。","ENG":"Monsters invaded the thornbush forest.","TWN":"荊棘森林裡有怪物入侵了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"내가 도착하기도 전에, 루가 혼자 전부 해치웠더라고.","JPN":"あたしが駆け付けたときには、すでにルーがすべて倒していた。","ENG":"But Lugh took care of them all before I even arrived.","TWN":"在我趕到時，露一個人已經解決了所有的問題。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그거 대단하네에-","JPN":"それはすごいわねー","ENG":"That's splendid.","TWN":"那真是厲害——"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"포상을 잔뜩 줘야겠는걸?","JPN":"たっぷりご褒美をあげなきゃね！","ENG":"I must give her a reward.","TWN":"得多給她點獎勵才行。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그런데… ","JPN":"しかし…… ","ENG":"However...","TWN":"不過…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 애는 왜 같이 안 온 거니? 많이 다치기라도 했어?","JPN":"あの子はどうして一緒に来なかったの？　深い怪我でも負ってしまったのかしら？","ENG":"Why is she not with you? Is she hurt?","TWN":"她為什麼沒一起來？是受了傷嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그게…","JPN":"それは……","ENG":"Well...","TWN":"這個…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"속이 안 좋아서 쉰대.","JPN":"具合が悪いみたいで、休みたいんだって。","ENG":"She's resting because she doesn't feel good.","TWN":"她說身體不舒服，所以回去休息了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"귀염둥이.","JPN":"可愛子ちゃん。","ENG":"Cutie.","TWN":"小可愛。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"넌 뭔가 숨기려 할 때 내 눈을 피하는 버릇이 있어.","JPN":"アナタは何かを隠しているとき、アタシから目を逸らす癖があるのよ。","ENG":"You have a habit of avoiding my eyes when you have something to hide.","TWN":"你每次想隱瞞什麼的時候，總是會避開我的眼睛。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"뭐, 뭐가! 내가 거짓말이라도 했다는 거야?","JPN":"な、なによ！　あたしが嘘でもついてるって言いたいの？","ENG":"W-what?! Are you saying that I'm lying to you?","TWN":"什…什麼！你是說我在撒謊嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 아이에게… 무슨 일이 생긴 거니?","JPN":"あの子に……何かあったの？","ENG":"Did something... happen to that child?","TWN":"那個孩子…發生了什麼事？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그…","JPN":"その……","ENG":"Um...","TWN":"那個…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"내가… 루를 옷가게로 데려갔어.","JPN":"あたしがルーを……仕立屋さんに連れていったの。","ENG":"I... took Lugh to the tailor shop.","TWN":"我…帶露去了服裝店。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"다른 사람들이 루의 몸을 봤고…","JPN":"みんながルーの身体を見てしまって……","ENG":"The others saw Lugh's body and...","TWN":"其他人看到了露的身體…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"거기엔… ","JPN":"それで…… ","ENG":"There...","TWN":"她身上…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"거기엔… 반역자의 낙인이 있었어.","JPN":"身体には……反逆者の烙印があったの。","ENG":"There... was the brand of the traitor.","TWN":"有…叛徒的烙印。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"어쩐지 분위기가 어수선하더라니.","JPN":"なるほど。それで村が少し騒々しかったのね。","ENG":"No wonder the streets were somewhat chaotic.","TWN":"難怪氣氛有點混亂。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L29_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"결국 우려하던 사단이 난 모양이구나.","JPN":"結局、杞憂していたことが起きてしまったわね。","ENG":"It seems that my concerns have come true.","TWN":"擔心的事…終究還是發生了呢。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"역시…!","JPN":"やっぱり……！","ENG":"I knew it...!","TWN":"果然…！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"멀린은 처음부터 그 낙인에 대해 알고 있었던 거지?","JPN":"マーリンは最初からあの烙印のこと、知っていたのね？","ENG":"You knew from the start about her mark, didn't you, Merlin?","TWN":"梅林從一開始就知道那個烙印的事，對吧？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"왜 나한테 말해주지 않았어?","JPN":"どうしてあたしに言ってくれなかったの？","ENG":"Why didn't you tell me?","TWN":"為什麼不告訴我？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"내가 알고 있었으면…!","JPN":"あたしがその事実を知ってさえいれば……！","ENG":"If I had known–!","TWN":"如果我知道的話…！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"만약 그랬다면…","JPN":"もし知っていたら……","ENG":"If I had told you...","TWN":"告訴你的話…"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"귀염둥이는 그 아이와 지금처럼 지낼 수 있었을까?","JPN":"可愛子ちゃんは、あの子と今のような関係になれたかしら？","ENG":"would you be as close with her as you are now, cutie?","TWN":"小可愛還能像現在這樣和那個孩子相處嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 아이가 악마와 계약할 운명이라는 걸 알면서도 말이야.","JPN":"あの子が悪魔と契約を結ぶ運命にあるということを知っていたとしても。","ENG":"Knowing that her fate was to form a pact with a devil?","TWN":"明知道那個孩子註定要和魔鬼簽下契約。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"루는 자기 목숨을 걸고 우릴 도와줬어.","JPN":"ルーは自分の命よりもあたしたちを助けることを優先してくれた。","ENG":"Lugh risked her life to help us.","TWN":"露冒著生命危險幫助了我們。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그런데, 난 호의랍시고…","JPN":"なのにあたしは、お礼のつもりで余計なことをして……","ENG":"But all I did was...","TWN":"但是，我自以為是的好意…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그 사람이 숨기고 싶어했던 비밀을 들춰버렸어.","JPN":"あの人が隠していた秘密を曝してしまった。","ENG":"reveal a secret she wanted hidden even though I meant goodwill.","TWN":"卻揭開了她想要隱藏的秘密。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"너무 바보 같잖아. 이런 건…","JPN":"あたしは大バカ者よ、こんなの……","ENG":"It's all so stupid...","TWN":"真是太傻了。這樣的事…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L43_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"처음부터 알고 있었다면.","JPN":"もし最初から知っていたら。","ENG":"If you had known from the beginning.","TWN":"如果從一開始就知道的話。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L44_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"넌 그 아이의 비밀을 지켜줬을까?","JPN":"アナタはあの子の秘密を守ってあげたのかしら？","ENG":"Would you have kept that child's secret?","TWN":"你還會守護那個孩子的秘密嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L45_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L46_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"나도 잘 모르겠어.","JPN":"自分でもわからない。","ENG":"I don't know.","TWN":"我也不太清楚。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L47_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"종말의 예언에 나오는 반역자는 사악한 사람일 거라고만 알았는데… ","JPN":"終末の予言に記される反逆者は、邪悪な人間だとばかり思っていたんだけど…… ","ENG":"I thought the traitor from the Apocalypse Augury would be an evil person...","TWN":"我只知道末日預言中的叛徒會是個邪惡的人…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L48_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"사람들을 돕는 모습을 보면서… 우연히 그 속마음을 엿듣게 되면서…","JPN":"人を助ける姿を見たり……偶然あの人の本心を聞いてしまって……","ENG":"but seeing her help others... and coincidentally hearing her true feelings...","TWN":"但我看到她幫助別人…也無意中聽到了她的心聲…"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L49_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"이젠… 싫어할 수가 없게 됐어.","JPN":"今更……嫌いにはなれなくなっちゃってる。","ENG":"Now... I can't hate her.","TWN":"現在…已經無法討厭她了。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L50_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"그 아이를 걱정하고 있구나.","JPN":"あの子のことが心配なのね。","ENG":"You are worried about her.","TWN":"你在擔心那個孩子啊。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L2_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"먼저 가세요.","JPN":"先に行ってください。","ENG":"You go on ahead first.","TWN":"你先走吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_LAUGH"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"너무 오래 매달려 있느라 지쳐서… 집에 돌아가서 쉬고 싶네요.","JPN":"かなり長い時間吊るされてしんどかったので……帰って少し休ませてください。","ENG":"I'm exhausted from hanging from a tree for so long that... I need some time to rest.","TWN":"被倒吊太久，很不舒服…我想回去休息一下。"},"stage":{"bg":"FOREST_NORMAL","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"내가 잘못된 걸까?","JPN":"全部あたしのせいなのかな。","ENG":"Am I at fault here?","TWN":"是我錯了嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그날 반역자를 동토에 내버려 뒀어야 했다고… 후회해야 하는 걸까?","JPN":"あの日、反逆者を凍土から連れてこなければよかったって……後悔するべきなのかな。","ENG":"Am I supposed to regret... that I should've just left that traitor in the gelid lands?","TWN":"那天應該把叛徒丟在凍土上…我該後悔嗎…？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"후회는 아무것도 바꿀 수 없어.","JPN":"後悔では、何も変えることはできないわよ。","ENG":"Regret changes nothing.","TWN":"後悔什麼也改變不了。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"옛 아발론이 모든 예언을 알면서도 결국 몰락을 피하지 못한 것처럼.","JPN":"かつてのアバロンがすべての予言を把握していたにも関わらず、結局は没落を避けられなかったようにね。","ENG":"Much like how the Old Avalon knew all its prophecies but could not avoid its fall.","TWN":"古老的阿瓦隆王國就算知道了所有的預言，最終也沒能逃脫滅亡。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"그럼 가르쳐줘, 멀린.","JPN":"じゃあ教えてよ、マーリン。","ENG":"Then tell me, Merlin.","TWN":"那就告訴我吧，梅林。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORGANA_ROOT_NULL_NULL","text":{"KOREA":"내가 어떻게 해야 하는 건지.","JPN":"あたしはどうすればいいの？","ENG":"What am I supposed to do?","TWN":"我們應該怎麼辦？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORGANA_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"우리가 예언을 통해 미래를 안다고 해서, 그저 가만히 순응해야 한다는 뜻은 아니야.","JPN":"予言によって未来を知っているとしても、ただそれを受け入れなければならないということではないわ。","ENG":"Even if we know the future through prophecies, it does not mean that we should accept it.","TWN":"就算我們能透過預言知曉未來，也不表示只能順從。"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MERLIN_ROOT_NULL_NULL","text":{"KOREA":"기왕이면 너에게 가장 후회 없는 선택을 하는 편이… 후련하지 않겠어?","JPN":"どうせなら、もっとも悔いのない選択をした方がいいんじゃない？","ENG":"Would it not be best for you to make decisions resulting in the fewest regrets?","TWN":"如果可以的話，做出讓你最不後悔的選擇…不是更好嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MERLIN_ROOT_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"또… 마물인가요?","JPN":"魔物……またですか。","ENG":"Monsters... again?","TWN":"又是…怪物嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_HATE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"당신들. 그루터기로 향하고 있는 거죠?","JPN":"あなたたち、切り株に行こうとしているんですね？","ENG":"Are you headed toward the Stump?","TWN":"你們，是要去木墩嗎？"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이렇게 계속 마주치는 걸 보면, 전 아무래도 사람보다 괴물과 연이 깊나 봐요.","JPN":"こうして何度も出くわすってことは、どうやら私は普通の人より化け物を引き寄せる運命のようです。","ENG":"Seeing how I keep bumping into you all, I guess I have more of a connection with monsters than I do with people.","TWN":"我老是遇到怪物，看來我和怪物的緣分比和人還要深。"},"stage":{"bg":"NOMAD_BORDER","bgm":"THEMA_CA_HUNTRESS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"그래요. 싸워보죠.","JPN":"いいでしょう。戦います。","ENG":"All right. Let's fight.","TWN":"好吧，戰鬥吧。"},"stage":{"bg":"NOMAD_BORDER","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORDRED_ROOT_NULL_LU","text":{"KOREA":"이젠 도망칠 이유도 없으니까.","JPN":"もう逃げる理由なんて、ないんですから。","ENG":"I have no reason to flee anymore.","TWN":"現在已經沒有逃跑的理由了。"},"stage":{"bg":"NOMAD_BORDER","bgm":"BATTLE_BOSS_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORDRED_ROOT_NULL_LU","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};